    int[] predModes = new int[16];
    byte[] predLeft = Arrays.copyOf(ctx.leftRow[0], 16);
    byte[] predTop = Arrays.copyOfRange(ctx.topLine[0], mbX << 4, (mbX << 4) + 16 + (mbX < ctx.mbWidth - 1 ? 4 : 0));
