        {4, 5, 6},
        {7, 8, 9}
    };

    short[][] tapsYs = {
        {1, 2, 3},
        {4, 5, 6},
        {7, 8, 9}
    };

    byte[] srcData = src.getPlaneData(p);
    byte[] dstData = dst.getPlaneData(p);
    int toSizeWidth = toSize.getWidth();

    int[] temp = new int[toSize.getWidth() * (src.getPlaneHeight(p) + taps)];

    // Horizontal pass
    for (int y = 0; y < src.getPlaneHeight(p) + taps; y++) {
